import os
import torch
from transformers import EsmTokenizer, EsmModel
from tqdm import tqdm #Using tqdm for progress bars for longer tasks

print("Step 4: Generating embeddings for G2019S LRRK2 using ESM-2 language model with sliding window")

print("\nStep 4.1: Initializing")

#checking terminal directory
print("CWD:",os.getcwd())
print("__file__:",__file__)

#FILE DIRECTORIES
new_data_dir='./new_data/'

#LRRK2 G2019S INFO
lrrk2_id='ENSP00000298910'
mutant_sequence=''

esm2_model='facebook/esm2_t36_3B_UR50D' #ESM2 model name

#Defining function to generate embeddings for better readability and debugging purposes
def generate_embeddings(mutant_sequence,model_name):
    if torch.backends.mps.is_available():
        device=torch.device('mps')
    else:
        device=torch.device('cpu')
    #mps is for mac; faster than cpu if available
    
    tokenizer=EsmTokenizer.from_pretrained(model_name)
    model=EsmModel.from_pretrained(model_name).to(device)
    model.eval()

    mutant_embedding=[]
    index=0
    while index<len(mutant_sequence):
        end=index+1022
        if end>len(mutant_sequence):
            end=len(mutant_sequence)
        window=mutant_sequence[index:end] #will be of length 1022 or less
        if len(window)>1022:
            window=window[:1022]  # ESM2 token limit is 1024, but two are special cases (beginning and end)
        inputs=tokenizer(window,return_tensors='pt',add_special_tokens=True).to(device)
        with torch.no_grad():
            outputs=model(**inputs)
        last_hidden_state=outputs.last_hidden_state
        embedding=last_hidden_state[0,1:-1].mean(dim=0)
        mutant_embedding.append(embedding.cpu())
        index+=511  # sliding window with overlap of 511 amino acids
    mutant_embedding=torch.stack(mutant_embedding).mean(dim=0)
    return mutant_embedding

print("\nStep 4.2: Generating and saving mutant LRRK2 G2019S embedding to file")
if __name__=="__main__":  
    mutant_embedding=generate_embeddings(mutant_sequence,esm2_model)
    mutant_output_file=os.path.join(new_data_dir,'g2019s_protein_embedding.pt')
    torch.save(mutant_embedding, mutant_output_file)
    print("Mutant LRRK2 G2019S embedding saved to:",mutant_output_file)